106→function truncateContent(content: string, maxLength: number): string {
107→  if (content.length <= maxLength) return content;
108→  return content.slice(0, maxLength) + '\u2026';
109→}
110→
111→function renderClipboardIcon(entry: ClipboardEntry): ReactNode {
112→  if (entry.contentType === 'color') {
113→    return <ColorDot color={entry.content} />;
114→  }
115→  if (entry.contentType === 'image') {
116→    return <ImageIcon />;
117→  }
118→  return entry.sourceIcon;
119→}
