  1→import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
  2→import type { EmojiCategory, EmojiEntry } from '../../data/emoji_data';
  3→import {
  4→  EMOJI_CATEGORIES,
  5→  EMOJI_CATEGORY_LABELS,
  6→  EMOJI_CATEGORY_ORDER,
  7→  MOCK_EMOJIS,
  8→} from '../../data/emoji_data';
  9→import { useDebounce } from '../../hooks/use_debounce';
 10→import { useHUD } from '../../hooks/use_hud';
 11→import { useKeyboardShortcut } from '../../hooks/use_keyboard_shortcut';
 12→import { useNavigation } from '../../hooks/use_navigation';
 13→import { settingsDb } from '../../utils/database';
 14→import { fuzzyMatch } from '../../utils/fuzzy_search';
 15→import { ActionPanel } from '../action_panel/action_panel';
 16→import { createCopyAction, performCopy } from '../action_panel/actions';
 17→import type { DropdownSection } from '../action_panel/actions_dropdown';
 18→import { EmptyState } from '../empty_state/empty_state';
 19→import { HUDContainer } from '../hud/hud_container';
 20→import { Kbd } from '../kbd/kbd';
 21→import { SearchBar } from '../search_bar/search_bar';
 22→import type { SearchDropdownSection } from '../search_bar/search_dropdown';
 23→import { SearchDropdown } from '../search_bar/search_dropdown';
 24→import './emoji_picker_view.scss';
 25→
 26→const COLUMNS = 6;
 27→const DB_KEY = 'emoji-recent';
 28→const MAX_RECENT = 12;
 29→
 30→function SearchEmptyIcon() {
 31→  return (
 32→    <svg width="48" height="48" viewBox="0 0 48 48" fill="none">
 33→      <circle cx="21" cy="21" r="12" stroke="currentColor" strokeWidth="3" />
 34→      <line
 35→        x1="30"
 36→        y1="30"
 37→        x2="42"
 38→        y2="42"
 39→        stroke="currentColor"
 40→        strokeWidth="3"
 41→        strokeLinecap="round"
 42→      />
 43→    </svg>
 44→  );
 45→}
 46→
 47→function parseRecentEmojis(raw: string | null): string[] {
 48→  if (!raw) return [];
 49→  try {
 50→    const parsed: unknown = JSON.parse(raw);
 51→    if (Array.isArray(parsed) && parsed.every(v => typeof v === 'string')) {
 52→      return parsed as string[];
 53→    }
 54→  } catch {
 55→    // invalid
 56→  }
 57→  return [];
 58→}
 59→
 60→interface EmojiSection {
 61→  title: string;
 62→  emojis: EmojiEntry[];
 63→}
 64→
 65→const FILTER_SECTIONS: SearchDropdownSection[] = [
 66→  {
 67→    options: [
 68→      {
 69→        label: 'All',
 70→        value: 'all',
 71→      },
 72→    ],
 73→  },
 74→  {
 75→    title: 'Category',
 76→    options: EMOJI_CATEGORIES.map(c => ({
 77→      label: c.label,
 78→      value: c.value,
 79→    })),
 80→  },
 81→];
 82→
 83→export function EmojiPickerView() {
 84→  const nav = useNavigation();
 85→  const [query, setQuery] = useState('');
 86→  const { debouncedValue: debouncedQuery } = useDebounce(query, 150);
 87→  const [filterValue, setFilterValue] = useState('all');
 88→  const [activeIndex, setActiveIndex] = useState(0);
 89→  const [actionsOpen, setActionsOpen] = useState(false);
 90→  const [recentChars, setRecentChars] = useState<string[]>([]);
 91→
 92→  useEffect(() => {
 93→    let cancelled = false;
 94→    settingsDb
 95→      .get(DB_KEY)
 96→      .then(raw => {
 97→        if (!cancelled) setRecentChars(parseRecentEmojis(raw));
 98→      })
 99→      .catch(console.error);
100→    return () => {
101→      cancelled = true;
102→    };
103→  }, []);
104→  const { items: hudItems, show: showHUD } = useHUD();
105→  const containerRef = useRef<HTMLDivElement>(null);
106→
107→  const emojiLookup = useMemo(() => {
108→    const map = new Map<string, EmojiEntry>();
109→    for (const e of MOCK_EMOJIS) {
110→      map.set(e.char, e);
111→    }
112→    return map;
113→  }, []);
114→
115→  const recentEmojis = useMemo(
116→    () =>
117→      recentChars
118→        .map(char => emojiLookup.get(char))
119→        .filter((e): e is EmojiEntry => e !== undefined),
120→    [
121→      recentChars,
122→      emojiLookup,
123→    ],
124→  );
125→
126→  const filtered = useMemo(() => {
127→    let emojis = MOCK_EMOJIS;
128→    if (filterValue !== 'all') {
129→      emojis = emojis.filter(e => e.category === filterValue);
130→    }
131→    if (debouncedQuery) {
132→      emojis = emojis.filter(
133→        e =>
134→          fuzzyMatch(debouncedQuery, e.name) ||
135→          e.keywords.some(k => fuzzyMatch(debouncedQuery, k)) ||
136→          e.char === debouncedQuery,
137→      );
138→    }
139→    return emojis;
140→  }, [
