122→function truncateContent(content: string, maxLength: number): string {
123→  const singleLine = content.replace(/\n/g, ' ');
124→  if (singleLine.length <= maxLength) return singleLine;
125→  return singleLine.slice(0, maxLength) + '\u2026';
126→}
