157→function NoteEditorView({ note, onSave }: NoteEditorViewProps) {
158→  const [title, setTitle] = useState(note?.title ?? '');
159→  const [content, setContent] = useState(note?.content ?? '');
160→  const [preview, setPreview] = useState(false);
161→  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
162→  const titleRef = useRef(title);
163→  const contentRef = useRef(content);
164→  const onSaveRef = useRef(onSave);
165→
166→  titleRef.current = title;
167→  contentRef.current = content;
168→  onSaveRef.current = onSave;
169→
170→  const debounceSave = useCallback(() => {
171→    if (debounceRef.current) clearTimeout(debounceRef.current);
172→    debounceRef.current = setTimeout(() => {
173→      onSaveRef.current(titleRef.current, contentRef.current);
174→    }, 500);
175→  }, []);
176→
177→  useEffect(() => {
178→    return () => {
179→      if (debounceRef.current) {
180→        clearTimeout(debounceRef.current);
181→        onSaveRef.current(titleRef.current, contentRef.current);
182→      }
183→    };
184→  }, []);
185→
186→  const handleTitleChange = useCallback(
187→    (e: React.ChangeEvent<HTMLInputElement>) => {
188→      setTitle(e.target.value);
189→      debounceSave();
190→    },
191→    [debounceSave],
192→  );
193→
194→  const handleContentChange = useCallback(
195→    (e: React.ChangeEvent<HTMLTextAreaElement>) => {
196→      setContent(e.target.value);
197→      debounceSave();
198→    },
199→    [debounceSave],
200→  );
201→
202→  const handleFlushSave = useCallback(() => {
203→    if (debounceRef.current) clearTimeout(debounceRef.current);
204→    onSaveRef.current(titleRef.current, contentRef.current);
205→  }, []);
206→
207→  const togglePreview = useCallback(() => {
208→    setPreview(prev => !prev);
209→  }, []);
210→
211→  useKeyboardShortcut(
212→    {
213→      key: 's',
214→      meta: true,
215→    },
216→    handleFlushSave,
217→  );
218→  useKeyboardShortcut(
219→    {
220→      key: 'p',
221→      meta: true,
222→      shift: true,
223→    },
224→    togglePreview,
225→  );
226→
227→  const renderedHtml = useMemo(
228→    () =>
229→      preview
230→        ? DOMPurify.sanitize(
231→            marked.parse(content || '*No content*', { async: false }),
232→          )
233→        : '',
234→    [
235→      content,
236→      preview,
237→    ],
238→  );
239→
240→  return (
241→    <div className="notes-editor">
242→      <div className="notes-editor__header">
