244→          className="notes-editor__title-input"
245→          type="text"
246→          value={title}
247→          onChange={handleTitleChange}
248→          placeholder="Note Title"
249→          aria-label="Note title"
250→          autoFocus={!preview}
251→          readOnly={preview}
252→        />
253→        <button
254→          className={`notes-editor__preview-toggle${preview ? ' notes-editor__preview-toggle--active' : ''}`}
255→          onClick={togglePreview}
256→          aria-label={
257→            preview ? 'Switch to edit mode' : 'Switch to preview mode'
258→          }
259→          aria-pressed={preview}
260→          type="button"
261→        >
262→          {preview ? 'Edit' : 'Preview'}
263→        </button>
264→      </div>
265→      {preview ? (
266→        <div
267→          className="notes-editor__preview detail__markdown"
268→          dangerouslySetInnerHTML={{ __html: renderedHtml }}
269→          role="document"
270→          aria-label="Markdown preview"
271→        />
272→      ) : (
273→        <textarea
274→          className="notes-editor__content-area"
275→          value={content}
276→          onChange={handleContentChange}
277→          placeholder="Start writing..."
278→          aria-label="Note content"
279→        />
280→      )}
281→      {note && (
282→        <div className="notes-editor__meta">
283→          <span>Modified {note.updatedAt.toLocaleString()}</span>
284→        </div>
285→      )}
286→    </div>
287→  );
