 96→function truncateContent(content: string, maxLength: number): string {
 97→  const singleLine = content.replace(/\n/g, ' ');
 98→  if (singleLine.length <= maxLength) return singleLine;
 99→  return singleLine.slice(0, maxLength) + '\u2026';
100→}
