108→function rowToEntry(row: SnippetRow): SnippetEntry {
109→  const parsed = new Date(row.created_at);
110→  const createdAt = isNaN(parsed.getTime()) ? new Date() : parsed;
111→
112→  let tags: SnippetEntry['tags'] = [];
113→  try {
114→    const raw = JSON.parse(row.tags);
115→    if (Array.isArray(raw)) {
116→      tags = raw.map((t: {
117→        text?: string;
118→        color?: string;
119→      }) => ({
120→        text: typeof t.text === 'string' ? t.text : '',
121→        color:
122→          typeof t.color === 'string' && isTagColor(t.color)
123→            ? t.color
124→            : undefined,
125→      }));
126→    }
127→  } catch {
128→    // empty
129→  }
130→
131→  return {
132→    id: row.id,
133→    name: row.name,
134→    keyword: row.keyword,
135→    content: row.content,
136→    category: isSnippetCategory(row.category) ? row.category : 'general',
137→    tags,
138→    createdAt,
139→  };
140→}
