142→function entryToRow(entry: SnippetEntry): SnippetRow {
143→  return {
144→    id: entry.id,
145→    name: entry.name,
146→    keyword: entry.keyword,
147→    content: entry.content,
148→    category: entry.category,
149→    tags: JSON.stringify(entry.tags),
150→    created_at: entry.createdAt.toISOString(),
151→  };
152→}
