  97→function isQuicklinkType(value: string): value is QuicklinkType {
  98→  return value === 'url' || value === 'file' || value === 'deeplink';
  99→}
 100→
 101→function rowToEntry(row: QuicklinkRow): QuicklinkEntry {
 102→  const parsed = new Date(row.created_at);
 103→  const createdAt = Number.isNaN(parsed.getTime()) ? new Date() : parsed;
 104→  const type = isQuicklinkType(row.type) ? row.type : 'url';
 105→
 106→  let tags:
 107→    | {
 108→        text: string;
 109→        color?: TagColor;
 110→      }[]
 111→    | undefined;
 112→  if (row.tags) {
 113→    try {
 114→      const rawTags = JSON.parse(row.tags);
 115→      if (Array.isArray(rawTags)) {
 116→        const validated = rawTags
 117→          .filter(
 118→            (
 119→              t,
 120→            ): t is {
 121→              text: string;
 122→              color?: string;
 123→            } =>
 124→              typeof t === 'object' && t !== null && typeof t.text === 'string',
 125→          )
 126→          .map(t => ({
 127→            text: t.text,
 128→            color:
 129→              typeof t.color === 'string' && isTagColor(t.color)
 130→                ? t.color
 131→                : undefined,
 132→          }));
 133→        if (validated.length > 0) {
 134→          tags = validated;
 135→        }
 136→      }
 137→    } catch {
 138→      /* empty */
 139→    }
 140→  }
 141→
 142→  return {
 143→    id: row.id,
 144→    name: row.name,
 145→    link: row.link,
 146→    type,
 147→    application: row.application ?? undefined,
 148→    icon: getQuicklinkIcon(type),
 149→    tags,
 150→    createdAt,
 151→  };
 152→}
 153→
 154→function entryToRow(entry: QuicklinkEntry): QuicklinkRow {
 155→  return {
 156→    id: entry.id,
 157→    name: entry.name,
 158→    link: entry.link,
 159→    type: entry.type,
 160→    application: entry.application ?? null,
 161→    tags: entry.tags ? JSON.stringify(entry.tags) : '[]',
 162→    created_at: entry.createdAt.toISOString(),
 163→  };
 164→}
