 116→function formatTime(time: string): string {
 117→  const parts = time.split(':').map(Number);
 118→  const hours = parts[0];
 119→  const minutes = parts[1];
 120→  if (
 121→    hours === undefined ||
 122→    isNaN(hours) ||
 123→    minutes === undefined ||
 124→    isNaN(minutes)
 125→  ) {
 126→    return time || '--:--';
 127→  }
 128→  const period = hours >= 12 ? 'PM' : 'AM';
 129→  const h = hours % 12 || 12;
 130→  return `${h}:${String(minutes).padStart(2, '0')} ${period}`;
 131→}
 132→
 133→function formatDueLabel(dueDate: Date, renderNow: Date): string {
 134→  const todayStart = new Date(renderNow);
 135→  todayStart.setHours(0, 0, 0, 0);
 136→  const dueStart = new Date(dueDate);
 137→  dueStart.setHours(0, 0, 0, 0);
 138→
 139→  const diffDays = Math.round(
 140→    (dueStart.getTime() - todayStart.getTime()) / (1000 * 60 * 60 * 24),
 141→  );
 142→
 143→  if (diffDays === 0) return 'Today';
 144→  if (diffDays === 1) return 'Tomorrow';
 145→  if (diffDays === -1) return 'Yesterday';
 146→  if (diffDays < 0) return `${Math.abs(diffDays)} days overdue`;
 147→  if (diffDays <= 7) return `In ${diffDays} days`;
 148→  return dueDate.toLocaleDateString(undefined, {
 149→    month: 'short',
 150→    day: 'numeric',
 151→  });
 152→}
 153→
 154→function repeatLabel(repeat: RepeatOption): string {
 155→  const found = REPEAT_OPTIONS.find(r => r.value === repeat);
 156→  return found?.label ?? 'None';
 157→}
