 159→function isSameDay(a: Date, b: Date): boolean {
 160→  return (
 161→    a.getFullYear() === b.getFullYear() &&
 162→    a.getMonth() === b.getMonth() &&
 163→    a.getDate() === b.getDate()
 164→  );
 165→}
