 167→function rowToEntry(row: ReminderRow): ReminderEntry {
 168→  const dueDate = new Date(row.due_date);
 169→  const completedAt = row.completed_at ? new Date(row.completed_at) : null;
 170→  const createdAt = new Date(row.created_at);
 171→  return {
 172→    id: row.id,
 173→    title: row.title,
 174→    dueDate: isNaN(dueDate.getTime()) ? new Date() : dueDate,
 175→    dueTime: row.due_time,
 176→    repeat: isRepeatOption(row.repeat) ? row.repeat : 'none',
 177→    notes: row.notes,
 178→    completed: row.completed === 1,
 179→    completedAt:
 180→      completedAt && !isNaN(completedAt.getTime()) ? completedAt : null,
 181→    createdAt: isNaN(createdAt.getTime()) ? new Date() : createdAt,
 182→  };
 183→}
