 185→function entryToRow(entry: ReminderEntry): ReminderRow {
 186→  return {
 187→    id: entry.id,
 188→    title: entry.title,
 189→    due_date: entry.dueDate.toISOString(),
 190→    due_time: entry.dueTime,
 191→    repeat: entry.repeat,
 192→    notes: entry.notes,
 193→    completed: entry.completed ? 1 : 0,
 194→    completed_at: entry.completedAt?.toISOString() ?? null,
 195→    created_at: entry.createdAt.toISOString(),
 196→  };
 197→}
