 363→  const [entries, setEntries] = useState<ReminderEntry[]>([]);
 364→  const [query, setQuery] = useState('');
 365→  const { debouncedValue: debouncedQuery } = useDebounce(query, 150);
 366→  const [filterValue, setFilterValue] = useState('all');
 367→  const [selectedIndex, setSelectedIndex] = useState(0);
 368→  const [actionsOpen, setActionsOpen] = useState(false);
 369→  const [subView, setSubView] = useState<ReminderSubView>('list');
