 371→    ReminderEntry | undefined
 372→  >();
 373→  const { items: hudItems, show: showHUD } = useHUD();
 374→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
 375→
 376→  useEffect(() => {
 377→    let aborted = false;
 378→
 379→    reminderDb
 380→      .getAll()
 381→      .then(rows => {
 382→        if (aborted) return;
 383→        if (rows.length > 0) {
 384→          setEntries(rows.map(rowToEntry));
 385→        } else if (!isTauri) {
 386→          const mock = MOCK_REMINDER_ENTRIES.map(e => ({ ...e }));
 387→          setEntries(mock);
 388→          Promise.all(mock.map(e => reminderDb.insert(entryToRow(e)))).catch(
 389→            console.error,
 390→          );
 391→        }
 392→      })
 393→      .catch(err => {
 394→        console.error('Failed to load reminders:', err);
 395→        if (!isTauri && !aborted) {
 396→          setEntries(MOCK_REMINDER_ENTRIES.map(e => ({ ...e })));
 397→        }
 398→      });
 399→
 400→    return () => {
 401→      aborted = true;
 402→    };
 403→  }, []);
 404→
 405→  const dbSearchFn = useCallback((q: string) => reminderDb.search(q), []);
 406→  const { results: ftsResults, invalidate: invalidateFts } = useDbSearch(
 407→    debouncedQuery,
 408→    dbSearchFn,
 409→    rowToEntry,
 410→  );
 411→
 412→  const filtered = useMemo(() => {
 413→    let items = ftsResults ?? entries;
 414→
 415→    if (filterValue === 'active') {
 416→      items = items.filter(e => !e.completed);
 417→    } else if (filterValue === 'completed') {
 418→      items = items.filter(e => e.completed);
 419→    }
 420→
 421→    if (!ftsResults && debouncedQuery) {
 422→      items = items.filter(
 423→        e =>
 424→          fuzzyMatch(debouncedQuery, e.title) ||
 425→          fuzzyMatch(debouncedQuery, e.notes),
 426→      );
 427→    }
 428→
 429→    return items;
 430→  }, [
 431→    entries,
 432→    debouncedQuery,
 433→    filterValue,
 434→    ftsResults,
 435→  ]);
 436→
 437→  const renderNow = useMemo(() => new Date(), []);
 438→
 439→  const sections = useMemo(() => {
 440→    const todayStart = new Date(renderNow);
 441→    todayStart.setHours(0, 0, 0, 0);
 442→    const tomorrowStart = new Date(todayStart);
 443→    tomorrowStart.setDate(tomorrowStart.getDate() + 1);
 444→
 445→    const overdue: ReminderEntry[] = [];
 446→    const today: ReminderEntry[] = [];
 447→    const upcoming: ReminderEntry[] = [];
 448→    const completed: ReminderEntry[] = [];
 449→
 450→    for (const entry of filtered) {
 451→      if (entry.completed) {
 452→        completed.push(entry);
 453→        continue;
 454→      }
 455→      const dueStart = new Date(entry.dueDate);
 456→      dueStart.setHours(0, 0, 0, 0);
 457→
 458→      if (dueStart.getTime() < todayStart.getTime()) {
 459→        overdue.push(entry);
 460→      } else if (isSameDay(dueStart, todayStart)) {
 461→        today.push(entry);
 462→      } else {
 463→        upcoming.push(entry);
 464→      }
 465→    }
 466→
 467→    return {
 468→      overdue,
 469→      today,
 470→      upcoming,
 471→      completed,
 472→    };
 473→  }, [
 474→    filtered,
 475→    renderNow,
 476→  ]);
 477→
