 1→import { useEffect, useRef, useState } from 'react';
 2→
 3→export function useDebounce<T>(value: T, delay: number): { debouncedValue: T; isPending: boolean } {
 4→  const [debouncedValue, setDebouncedValue] = useState(value);
 5→  const [isPending, setIsPending] = useState(false);
 6→  const previousValueRef = useRef(value);
 7→
 8→  useEffect(() => {
 9→    if (Object.is(value, previousValueRef.current)) {
10→      return;
11→    }
12→    previousValueRef.current = value;
13→    setIsPending(true);
14→
15→    const timer = setTimeout(() => {
16→      setDebouncedValue(value);
17→      setIsPending(false);
18→    }, delay);
19→
20→    return () => {
21→      clearTimeout(timer);
22→    };
23→  }, [value, delay]);
24→
25→  return { debouncedValue, isPending };
26→}
